from elasticsearch import Elasticsearch
from datetime import datetime
import logging
import json

class CentralizedLogger:
    def __init__(self, es_host="localhost", es_port=9200):
        self.es = Elasticsearch([f"{es_host}:{es_port}"])
        self.index_name = "logs"
        self._create_index()
        
    def _create_index(self):
        if not self.es.indices.exists(index=self.index_name):
            mapping = {
                "mappings": {
                    "properties": {
                        "timestamp": {"type": "date"},
                        "level": {"type": "keyword"},
                        "message": {"type": "text"},
                        "service": {"type": "keyword"},
                        "host": {"type": "keyword"},
                        "tags": {"type": "keyword"}
                    }
                }
            }
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def log(self, level, message, service="unknown", host="localhost", tags=None):
        log_entry = {
            "timestamp": datetime.utcnow().isoformat(),
            "level": level,
            "message": message,
            "service": service,
            "host": host,
            "tags": tags or []
        }
        
        self.es.index(
            index=self.index_name,
            body=log_entry
        )
    
    def search_logs(self, query, size=100, from_=0):
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "best_fields",
                    "fields": ["message", "service", "host", "tags"]
                }
            },
            "size": size,
            "from": from_,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        response = self.es.search(index=self.index_name, body=search_body)
        return response['hits']['hits']
    
    def search_logs_by_level(self, level, size=100):
        search_body = {
            "query": {
                "term": {
                    "level": level
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        response = self.es.search(index=self.index_name, body=search_body)
        return response['hits']['hits']
    
    def search_logs_by_service(self, service, size=100):
        search_body = {
            "query": {
                "term": {
                    "service": service
                }
            },
            "size": size,
            "sort": [{"timestamp": {"order": "desc"}}]
        }
        
        response = self.es.search(index=self.index_name, body=search_body)
        return response['hits']['hits']
    
    def get_log_stats(self):
        stats_body = {
            "aggs": {
                "levels": {
                    "terms": {"field": "level"}
                },
                "services": {
                    "terms": {"field": "service"}
                },
                "hosts": {
                    "terms": {"field": "host"}
                }
            }
        }
        
        response = self.es.search(index=self.index_name, body=stats_body)
        return response['aggregations']

